+import { NextRequest, NextResponse } from 'next/server';
+import { query } from '@/storage/database/pg-client';
+
+// POST /api/admin/energy-adjust - 管理员调整会员能量值
+export async function POST(request: NextRequest) {
+  try {
+    const body = await request.json();
+    const { userId, action, amount, note, adminId } = body;
+
+    // 验证参数
+    if (!userId || !action || !amount) {
+      return NextResponse.json(
+        { success: false, error: '缺少必要参数: userId, action, amount' },
+        { status: 400 }
+      );
+    }
+
+    if (!['add', 'deduct'].includes(action)) {
+      return NextResponse.json(
+        { success: false, error: 'action 必须是 add 或 deduct' },
+        { status: 400 }
+      );
+    }
+
+    const parsedAmount = parseInt(amount);
+    if (isNaN(parsedAmount) || parsedAmount <= 0) {
+      return NextResponse.json(
+        { success: false, error: 'amount 必须是正整数' },
+        { status: 400 }
+      );
+    }
+
+    // 验证管理员角色
+    if (adminId) {
+      const adminCheck = await query(
+        'SELECT role FROM users WHERE id = $1',
+        [adminId]
+      );
+      if (!adminCheck.length || adminCheck[0].role !== 'admin') {
+        return NextResponse.json(
+          { success: false, error: '权限不足: 仅管理员可执行此操作' },
+          { status: 403 }
+        );
+      }
+    }
+
+    // 获取目标用户当前能量值
+    const userCheck = await query(
+      'SELECT id, username, energy_value FROM users WHERE id = $1 AND role = $2',
+      [userId, 'member']
+    );
+    if (!userCheck.length) {
+      return NextResponse.json(
+        { success: false, error: '用户不存在或角色不是会员' },
+        { status: 404 }
+      );
+    }
+
+    const user = userCheck[0];
+    const beforeValue = Number(user.energy_value);
+    const deltaAmount = action === 'add' ? parsedAmount : -parsedAmount;
+    const afterValue = beforeValue + deltaAmount;
+
+    // 如果是扣减，验证能量值是否足够
+    if (action === 'deduct' && afterValue < 0) {
+      return NextResponse.json(
+        { success: false, error: `能量值不足，当前余额: ${beforeValue}` },
+        { status: 400 }
+      );
+    }
+
+    // 更新用户能量值
+    await query(
+      'UPDATE users SET energy_value = $1, updated_at = NOW() WHERE id = $2',
+      [afterValue, userId]
+    );
+
+    // 同步能量账户表
+    await query(
+      `INSERT INTO energy_accounts (user_id, balance, updated_at)
+       VALUES ($1, $2, NOW())
+       ON CONFLICT (user_id) DO UPDATE SET balance = $2, updated_at = NOW()`,
+      [userId, afterValue]
+    );
+
+    // 记录流水
+    const txType = action === 'add' ? 'manual_add' : 'manual_deduct';
+    await query(
+      `INSERT INTO energy_transactions 
+       (from_user_id, to_user_id, type, amount, note, status, created_at)
+       VALUES ($1, $2, $3, $4, $5, $6, NOW())`,
+      [adminId || 'admin', userId, txType, Math.abs(deltaAmount), note || '', 'completed']
+    );
+
+    // 发送通知
+    const notifyType = action === 'add' ? 'energy_added' : 'energy_deducted';
+    const notifyMessage = action === 'add'
+      ? `管理员调整: 能量值增加 ${parsedAmount}`
+      : `管理员调整: 能量值扣减 ${parsedAmount}`;
+    
+    await query(
+      `INSERT INTO notifications (user_id, type, title, message, is_read, created_at)
+       VALUES ($1, $2, $3, $4, false, NOW())`,
+      [userId, notifyType, '能量值调整通知', notifyMessage]
+    );
+
+    return NextResponse.json({
+      success: true,
+      data: {
+        userId,
+        username: user.username,
+        action,
+        amount: parsedAmount,
+        beforeValue,
+        afterValue,
+        note: note || '',
+      },
+      message: '能量值调整成功',
+    });
+
+  } catch (error: any) {
+    console.error('能量值调整失败:', error);
+    return NextResponse.json(
+      { success: false, error: error.message },
+      { status: 500 }
+    );
+  }
+}

