+/**
+ * Centralized utility module for dynamic input pattern handling.
+ * This module serves as the single source of truth for all input placeholder patterns and operations.
+ */
+
+// Raw LLM output pattern: INPUT_REQUIRED delimiters
+export const INPUT_REQUIRED_REGEX = /\[\[INPUT_REQUIRED:([^\]]+)\]\]/g;
+
+// Current placeholder format: %%DINPUT_...%%
+export const DINPUT_PLACEHOLDER_REGEX = /%%DINPUT_([^%]+)%%/g;
+
+// Legacy placeholder format: __DYNAMIC_INPUT_...__
+export const LEGACY_PLACEHOLDER_REGEX = /__DYNAMIC_INPUT_([^_]+)__/g;
+
+// Legacy raw token pattern
+export const LEGACY_RAW_TOKEN_REGEX = /__DYNAMIC_([^_]+)__/g;
+
+/**
+ * Checks if text contains any form of input placeholder.
+ * @param {string} text - The text to check
+ * @returns {boolean} - True if text contains any input placeholder pattern
+ */
+export function hasInputPatterns(text) {
+    if (!text || typeof text !== 'string') {
+        return false;
+    }
+    return INPUT_REQUIRED_REGEX.test(text)
+        || DINPUT_PLACEHOLDER_REGEX.test(text)
+        || LEGACY_PLACEHOLDER_REGEX.test(text)
+        || LEGACY_RAW_TOKEN_REGEX.test(text);
+}
+
+/**
+ * Cleans all input-related patterns from text.
+ * @param {string} text - The text to clean
+ * @param {string} [replacement] - The replacement string for matched patterns
+ * @returns {string} - Text with all input patterns removed or replaced
+ */
+export function cleanInputPatterns(text, replacement) {
+    if (!text || typeof text !== 'string') {
+        return text;
+    }
+    replacement = replacement !== undefined ? replacement : '';
+    
+    let cleaned = text;
+    cleaned = cleaned.replace(INPUT_REQUIRED_REGEX, replacement);
+    cleaned = cleaned.replace(DINPUT_PLACEHOLDER_REGEX, replacement);
+    cleaned = cleaned.replace(LEGACY_PLACEHOLDER_REGEX, replacement);
+    cleaned = cleaned.replace(LEGACY_RAW_TOKEN_REGEX, replacement);
+    
+    return cleaned;
+}
+
+/**
+ * Generates a markdown-safe placeholder token using %%DINPUT_ delimiters.
+ * @param {string} inputId - The input identifier
+ * @returns {string} - A formatted placeholder token
+ */
+export function makePlaceholder(inputId) {
+    return '%%DINPUT_' + inputId + '%%';
+}

