--- a/app/src/utils/inputPatterns.js
+++ b/app/src/utils/inputPatterns.js
@@ -0,0 +1,72 @@
+/**
+ * Single source of truth for dynamic input placeholder patterns.
+ *
+ * All files that detect, clean, or generate INPUT_REQUIRED / DINPUT
+ * placeholders MUST import from here. No inline regex allowed elsewhere.
+ */
+
+// ── Pattern Constants ────────────────────────────────────────────────
+/** Raw LLM output pattern: [[INPUT_REQUIRED:{Label}]] or [[INPUT_REQUIRED:Label]] */
+export const INPUT_REQUIRED_REGEX = /\[\[INPUT_REQUIRED:([^\]]+)\]\]/g;
+
+/** Current placeholder format (markdown-safe) */
+export const DINPUT_PLACEHOLDER_REGEX = /%%DINPUT_[A-Za-z0-9_-]+%%/g;
+
+/** Legacy placeholder that conflicted with markdown bold/italic */
+export const LEGACY_PLACEHOLDER_REGEX = /__DYNAMIC_INPUT_[A-Za-z0-9_-]+__/g;
+
+/** Raw tokens left after markdown stripped the surrounding underscores */
+export const LEGACY_RAW_TOKEN_REGEX = /DYNAMIC_INPUT_[A-Za-z0-9_-]+/g;
+
+// ── Detection ────────────────────────────────────────────────────────
+/**
+ * Returns true when text contains any form of input placeholder
+ * (raw LLM pattern, current format, or legacy formats).
+ */
+export function hasInputPatterns(text) {
+  if (!text || typeof text !== 'string') return false;
+  return (
+    text.includes('[[INPUT_REQUIRED:') ||
+    text.includes('%%DINPUT_') ||
+    text.includes('__DYNAMIC_INPUT_') ||
+    LEGACY_RAW_TOKEN_REGEX.test(text)
+  );
+}
+
+// ── Cleanup ──────────────────────────────────────────────────────────
+/**
+ * Strips ALL input-related patterns from text (current + legacy).
+ * Use this everywhere you need clean text for display, voice, etc.
+ *
+ * @param {string} text - Raw text that may contain input patterns
+ * @param {string} replacement - What to replace with (' ' for speech, '' for display)
+ * @returns {string} Cleaned text
+ */
+export function cleanInputPatterns(text, replacement = '') {
+  if (!text || typeof text !== 'string') return text || '';
+
+  return text
+    .replace(INPUT_REQUIRED_REGEX, replacement)
+    .replace(DINPUT_PLACEHOLDER_REGEX, replacement)
+    .replace(LEGACY_PLACEHOLDER_REGEX, replacement)
+    .replace(LEGACY_RAW_TOKEN_REGEX, replacement)
+    .replace(/<div[^>]*dynamic-input-placeholder[^>]*><\/div>/g, replacement)
+    .replace(/<div class="mt-4[\s\S]*?dynamic-input-placeholder[\s\S]*?<\/div>\s*<\/div>/g, replacement)
+    .trim();
+}
+
+// ── Placeholder Generation ───────────────────────────────────────────
+/**
+ * Creates a markdown-safe placeholder token for a given input ID.
+ * Uses %% delimiters which are NOT interpreted by markdown parsers.
+ */
+export function makePlaceholder(inputId) {
+  return `%%DINPUT_${inputId}%%`;
+}
+
+/**
+ * Creates a regex that matches a specific placeholder by input ID.
+ */
+export function placeholderRegex(inputId) {
+  return new RegExp(`%%DINPUT_${inputId.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}%%`, 'g');
+}
