@@ -0,0 +1,103 @@
+-- ============================================================
+-- WhatsApp Sync Flow Overhaul Migration
+-- Creates tables for instances, contacts, proper indexes
+-- ============================================================
+
+-- Create whatsapp_instances table (stores user's explicit instance assignment)
+CREATE TABLE IF NOT EXISTS whatsapp_instances (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
+  instance_name TEXT NOT NULL,
+  is_active BOOLEAN DEFAULT true,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW(),
+  UNIQUE(user_id, instance_name)
+);
+
+-- Create whatsapp_contacts table
+CREATE TABLE IF NOT EXISTS whatsapp_contacts (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,
+  instance_name TEXT NOT NULL,
+  remote_jid TEXT NOT NULL,
+  push_name TEXT,
+  profile_pic_url TEXT,
+  wa_id TEXT,
+  is_business BOOLEAN DEFAULT false,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW(),
+  UNIQUE(instance_name, remote_jid)
+);
+
+-- Add columns to existing whatsapp_chats if not exists
+DO $$
+BEGIN
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_chats' AND column_name = 'user_id') THEN
+    ALTER TABLE whatsapp_chats ADD COLUMN user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_chats' AND column_name = 'instance_name') THEN
+    ALTER TABLE whatsapp_chats ADD COLUMN instance_name TEXT;
+  END IF;
+END $$;
+
+-- Add columns to existing whatsapp_messages if not exists
+DO $$
+BEGIN
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'user_id') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'instance_name') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN instance_name TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'remote_jid') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN remote_jid TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'message_key') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN message_key TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'from_me') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN from_me BOOLEAN;
+  END IF;
+END $$;
+
+-- Add unique index for whatsapp_messages upsert (instance_name + remote_jid + message_key)
+CREATE UNIQUE INDEX IF NOT EXISTS whatsapp_messages_unique_msg 
+ON whatsapp_messages(instance_name, remote_jid, message_key) 
+WHERE message_key IS NOT NULL;
+
+-- Add index for whatsapp_chats if not exists
+CREATE INDEX IF NOT EXISTS whatsapp_chats_instance_remote_idx 
+ON whatsapp_chats(instance_name, remote_jid);
+
+-- Add index for whatsapp_contacts
+CREATE INDEX IF NOT EXISTS whatsapp_contacts_instance_remote_idx 
+ON whatsapp_contacts(instance_name, remote_jid);
+
+-- Create increment_unread_count function
+CREATE OR REPLACE FUNCTION increment_unread_count(p_instance_name TEXT, p_remote_jid TEXT)
+RETURNS VOID AS $$
+BEGIN
+  UPDATE whatsapp_chats 
+  SET unread_count = COALESCE(unread_count, 0) + 1,
+      updated_at = NOW()
+  WHERE instance_name = p_instance_name 
+    AND remote_jid = p_remote_jid;
+END;
+$$ LANGUAGE plpgsql;
+
+-- Enable RLS on new tables
+ALTER TABLE whatsapp_instances ENABLE ROW LEVEL SECURITY;
+ALTER TABLE whatsapp_contacts ENABLE ROW LEVEL SECURITY;
+
+-- RLS policies for authenticated users
+CREATE POLICY "Users can view own instances" ON whatsapp_instances
+  FOR SELECT USING (auth.uid() = user_id);
+
+CREATE POLICY "Users can manage own instances" ON whatsapp_instances
+  FOR ALL USING (auth.uid() = user_id);
+
+CREATE POLICY "Users can view own contacts" ON whatsapp_contacts
+  FOR SELECT USING (auth.uid() = user_id);
+
+CREATE POLICY "Users can manage own contacts" ON whatsapp_contacts
+  FOR ALL USING (auth.uid() = user_id);

