new file mode 100644
index 0000000..39add26
--- /dev/null
+++ b/components/jarvis/AudioVisualizer.jsx
@@ -0,0 +1,113 @@
+"use client";
+
+import React, { useEffect, useRef } from 'react';
+
+const AudioVisualizer = ({ isSpeaking = false, size = 80 }) => {
+  const canvasRef = useRef(null);
+  const animationRef = useRef(null);
+  const frequencyDataRef = useRef(new Uint8Array(64).fill(0));
+
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+
+    const ctx = canvas.getContext('2d');
+    const dpr = window.devicePixelRatio || 1;
+    const displaySize = size;
+    
+    canvas.width = displaySize * dpr;
+    canvas.height = displaySize * dpr;
+    ctx.scale(dpr, dpr);
+
+    const centerX = displaySize / 2;
+    const centerY = displaySize / 2;
+    const baseRadius = displaySize / 3;
+    const numBars = 48;
+
+    const draw = () => {
+      ctx.clearRect(0, 0, displaySize, displaySize);
+
+      // Update frequency data
+      for (let i = 0; i < numBars; i++) {
+        if (isSpeaking) {
+          // Generate random mock frequency data when speaking
+          frequencyDataRef.current[i] = Math.random() * 0.6 + 0.4;
+        } else {
+          // Decay smoothly when not speaking
+          frequencyDataRef.current[i] *= 0.9;
+        }
+      }
+
+      // Draw arc reactor visualization
+      const barWidth = (2 * Math.PI * baseRadius) / numBars - 2;
+
+      for (let i = 0; i < numBars; i++) {
+        const angle = (i / numBars) * Math.PI * 2 - Math.PI / 2;
+        const amplitude = frequencyDataRef.current[i];
+        const innerRadius = baseRadius - 5;
+        const outerRadius = innerRadius + amplitude * 20 + 8;
+
+        const x1 = centerX + Math.cos(angle) * innerRadius;
+        const y1 = centerY + Math.sin(angle) * innerRadius;
+        const x2 = centerX + Math.cos(angle) * outerRadius;
+        const y2 = centerY + Math.sin(angle) * outerRadius;
+
+        const gradient = ctx.createLinearGradient(x1, y1, x2, y2);
+        gradient.addColorStop(0, `rgba(79, 195, 247, ${0.3 + amplitude * 0.7})`);
+        gradient.addColorStop(1, `rgba(79, 195, 247, ${0.1 + amplitude * 0.5})`);
+
+        ctx.beginPath();
+        ctx.moveTo(x1, y1);
+        ctx.lineTo(x2, y2);
+        ctx.strokeStyle = gradient;
+        ctx.lineWidth = barWidth;
+        ctx.lineCap = 'round';
+        ctx.stroke();
+      }
+
+      // Draw center circle
+      const centerGradient = ctx.createRadialGradient(
+        centerX, centerY, 0,
+        centerX, centerY, baseRadius - 8
+      );
+      centerGradient.addColorStop(0, 'rgba(79, 195, 247, 0.3)');
+      centerGradient.addColorStop(0.5, 'rgba(79, 195, 247, 0.1)');
+      centerGradient.addColorStop(1, 'rgba(79, 195, 247, 0)');
+
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, baseRadius - 8, 0, Math.PI * 2);
+      ctx.fillStyle = centerGradient;
+      ctx.fill();
+
+      // Draw outer ring
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, baseRadius + 12, 0, Math.PI * 2);
+      ctx.strokeStyle = 'rgba(79, 195, 247, 0.2)';
+      ctx.lineWidth = 1;
+      ctx.stroke();
+
+      animationRef.current = requestAnimationFrame(draw);
+    };
+
+    draw();
+
+    return () => {
+      if (animationRef.current) {
+        cancelAnimationFrame(animationRef.current);
+      }
+    };
+  }, [isSpeaking, size]);
+
+  return (
+    <canvas
+      ref={canvasRef}
+      style={{
+        width: size,
+        height: size,
+      }}
+      className="drop-shadow-[0_0_10px_rgba(79,195,247,0.3)]"
+    />
+  );
+};
+
+export default AudioVisualizer;
diff --git a/components/jarvis/TypewriterText.jsx b/components/jarvis/TypewriterText.jsx
new file mode 100644
index 0000000..a0624e1
--- /dev/null
+++ b/components/jarvis/TypewriterText.jsx
@@ -0,0 +1,50 @@
+"use client";
+
+import React, { useState, useEffect, useRef } from 'react';
+
+const TypewriterText = ({ text, speed = 20, onUpdate }) => {
+  const [displayedText, setDisplayedText] = useState('');
+  const [isTyping, setIsTyping] = useState(false);
+  const indexRef = useRef(0);
+  const textRef = useRef(text);
+
+  useEffect(() => {
+    // Reset when text prop changes
+    if (text !== textRef.current) {
+      textRef.current = text;
+      indexRef.current = 0;
+      setDisplayedText('');
+      setIsTyping(true);
+    }
+  }, [text]);
+
+  useEffect(() => {
+    if (!text) return;
+
+    if (displayedText.length === 0 && text.length > 0) {
+      setIsTyping(true);
+    }
+
+    if (indexRef.current >= text.length) {
+      setIsTyping(false);
+      return;
+    }
+
+    const timeout = setTimeout(() => {
+      const nextChar = text[indexRef.current];
+      indexRef.current += 1;
+      const newText = displayedText + nextChar;
+      setDisplayedText(newText);
+      
+      if (onUpdate) {
+        onUpdate(newText);
+      }
+    }, speed);
+
+    return () => clearTimeout(timeout);
+  }, [displayedText, text, speed, onUpdate]);
+
+  return <span>{displayedText}</span>;
+};
+
+export default TypewriterText;

