--- /dev/null
+++ b/components/jarvis/TypewriterText.jsx
@@ -0,0 +1,55 @@
+"use client";
+
+import { useState, useEffect, useRef, useCallback } from 'react';
+
+/**
+ * TypewriterText: Renders text character by character with a typewriter effect.
+ * Mimics streaming LLM output and calls onUpdate on each character reveal.
+ */
+const TypewriterText = ({ text, speed = 20, onUpdate }) => {
+  const [displayedText, setDisplayedText] = useState('');
+  const [isComplete, setIsComplete] = useState(false);
+  const previousTextRef = useRef(text);
+  const timeoutRef = useRef(null);
+
+  useEffect(() => {
+    // Reset when text prop changes
+    if (text !== previousTextRef.current) {
+      previousTextRef.current = text;
+      setDisplayedText('');
+      setIsComplete(false);
+      
+      if (timeoutRef.current) {
+        clearTimeout(timeoutRef.current);
+      }
+    }
+
+    // If text is empty or already complete, nothing to do
+    if (!text || isComplete) return;
+
+    const currentLength = displayedText.length;
+    
+    if (currentLength < text.length) {
+      // Add next character after delay
+      timeoutRef.current = setTimeout(() => {
+        const nextChar = text[currentLength];
+        setDisplayedText(prev => prev + nextChar);
+        if (onUpdate) {
+          onUpdate(displayedText + nextChar);
+        }
+      }, speed);
+    } else {
+      setIsComplete(true);
+    }
+
+    return () => {
+      if (timeoutRef.current) {
+        clearTimeout(timeoutRef.current);
+      }
+    };
+  }, [text, displayedText, speed, onUpdate, isComplete]);
+
+  return <span>{displayedText}</span>;
+};
+
+export default TypewriterText;

