@@ -0,0 +1,236 @@
+"use server";
+
+import { auth } from "@/lib/auth";
+import { prisma } from "@/lib/db";
+import { revalidatePath } from "next/cache";
+import { z } from "zod";
+import { Prisma } from "@prisma/client";
+
+const SiteStatus = {
+  ACTIVE: "ACTIVE",
+  ARCHIVED: "ARCHIVED",
+} as const;
+
+const createSiteSchema = z.object({
+  name: z.string().min(1, "Site name is required"),
+  code: z.string().optional(),
+  address: z.string().optional(),
+  contactName: z.string().optional(),
+  contactPhone: z.string().optional(),
+  emergencyContact: z.string().optional(),
+  musterPoint: z.string().optional(),
+  openedAt: z.string().optional().nullable(),
+  closedAt: z.string().optional().nullable(),
+  notes: z.string().optional(),
+});
+
+const updateSiteSchema = createSiteSchema;
+
+export async function createSite(formData: FormData) {
+  const session = await auth();
+  if (!session?.user?.organizationId) {
+    return { error: "Not authenticated" };
+  }
+
+  const organizationId = session.user.organizationId;
+  const role = session.user.role;
+
+  if (role !== "ORG_ADMIN" && role !== "SUPER_ADMIN") {
+    return { error: "Only Org Admins can create sites" };
+  }
+
+  const rawData = {
+    name: formData.get("name"),
+    code: formData.get("code") || undefined,
+    address: formData.get("address") || undefined,
+    contactName: formData.get("contactName") || undefined,
+    contactPhone: formData.get("contactPhone") || undefined,
+    emergencyContact: formData.get("emergencyContact") || undefined,
+    musterPoint: formData.get("musterPoint") || undefined,
+    openedAt: formData.get("openedAt") || undefined,
+    closedAt: formData.get("closedAt") || undefined,
+    notes: formData.get("notes") || undefined,
+  };
+
+  const parsed = createSiteSchema.safeParse(rawData);
+  if (!parsed.success) {
+    return { error: parsed.error.errors[0].message };
+  }
+
+  const data = parsed.data;
+
+  try {
+    const site = await prisma.site.create({
+      data: {
+        name: data.name,
+        code: data.code,
+        address: data.address,
+        contactName: data.contactName,
+        contactPhone: data.contactPhone,
+        emergencyContact: data.emergencyContact,
+        musterPoint: data.musterPoint,
+        openedAt: data.openedAt ? new Date(data.openedAt) : null,
+        closedAt: data.closedAt ? new Date(data.closedAt) : null,
+        notes: data.notes,
+        organizationId,
+      },
+    });
+
+    revalidatePath("/admin/settings/sites");
+    revalidatePath("/admin/settings/sites/[id]", "page");
+    return { success: true, site };
+  } catch (err) {
+    if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2002") {
+      return { error: "A site with this name already exists in your organization" };
+    }
+    console.error("createSite error:", err);
+    return { error: "Failed to create site" };
+  }
+}
+
+export async function updateSite(siteId: string, formData: FormData) {
+  const session = await auth();
+  if (!session?.user?.organizationId) {
+    return { error: "Not authenticated" };
+  }
+
+  const organizationId = session.user.organizationId;
+  const role = session.user.role;
+
+  if (role !== "ORG_ADMIN" && role !== "SUPER_ADMIN") {
+    return { error: "Only Org Admins can update sites" };
+  }
+
+  const existing = await prisma.site.findUnique({
+    where: { id: siteId },
+    select: { organizationId: true },
+  });
+
+  if (!existing) {
+    return { error: "Site not found" };
+  }
+
+  if (role !== "SUPER_ADMIN" && existing.organizationId !== organizationId) {
+    return { error: "Access denied" };
+  }
+
+  const rawData = {
+    name: formData.get("name"),
+    code: formData.get("code") || undefined,
+    address: formData.get("address") || undefined,
+    contactName: formData.get("contactName") || undefined,
+    contactPhone: formData.get("contactPhone") || undefined,
+    emergencyContact: formData.get("emergencyContact") || undefined,
+    musterPoint: formData.get("musterPoint") || undefined,
+    openedAt: formData.get("openedAt") || undefined,
+    closedAt: formData.get("closedAt") || undefined,
+    notes: formData.get("notes") || undefined,
+  };
+
+  const parsed = updateSiteSchema.safeParse(rawData);
+  if (!parsed.success) {
+    return { error: parsed.error.errors[0].message };
+  }
+
+  const data = parsed.data;
+
+  try {
+    const site = await prisma.site.update({
+      where: { id: siteId },
+      data: {
+        name: data.name,
+        code: data.code,
+        address: data.address,
+        contactName: data.contactName,
+        contactPhone: data.contactPhone,
+        emergencyContact: data.emergencyContact,
+        musterPoint: data.musterPoint,
+        openedAt: data.openedAt ? new Date(data.openedAt) : null,
+        closedAt: data.closedAt ? new Date(data.closedAt) : null,
+        notes: data.notes,
+      },
+    });
+
+    revalidatePath("/admin/settings/sites");
+    revalidatePath("/admin/settings/sites/[id]", "page");
+    return { success: true, site };
+  } catch (err) {
+    if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2002") {
+      return { error: "A site with this name already exists in your organization" };
+    }
+    console.error("updateSite error:", err);
+    return { error: "Failed to update site" };
+  }
+}
+
+export async function setSiteStatus(siteId: string) {
+  const session = await auth();
+  if (!session?.user?.organizationId) {
+    return { error: "Not authenticated" };
+  }
+
+  const organizationId = session.user.organizationId;
+  const role = session.user.role;
+
+  if (role !== "ORG_ADMIN" && role !== "SUPER_ADMIN") {
+    return { error: "Only Org Admins can change site status" };
+  }
+
+  const existing = await prisma.site.findUnique({
+    where: { id: siteId },
+    select: { organizationId: true, status: true },
+  });
+
+  if (!existing) {
+    return { error: "Site not found" };
+  }
+
+  if (role !== "SUPER_ADMIN" && existing.organizationId !== organizationId) {
+    return { error: "Access denied" };
+  }
+
+  const newStatus = existing.status === "ACTIVE" ? "ARCHIVED" : "ACTIVE";
+
+  const site = await prisma.site.update({
+    where: { id: siteId },
+    data: { status: newStatus },
+  });
+
+  revalidatePath("/admin/settings/sites");
+  revalidatePath("/admin/settings/sites/[id]", "page");
+  return { success: true, site };
+}
+
+export async function deleteSite(siteId: string) {
+  const session = await auth();
+  if (!session?.user?.organizationId) {
+    return { error: "Not authenticated" };
+  }
+
+  const organizationId = session.user.organizationId;
+  const role = session.user.role;
+
+  if (role !== "ORG_ADMIN" && role !== "SUPER_ADMIN") {
+    return { error: "Only Org Admins can delete sites" };
+  }
+
+  const existing = await prisma.site.findUnique({
+    where: { id: siteId },
+    select: { organizationId: true },
+  });
+
+  if (!existing) {
+    return { error: "Site not found" };
+  }
+
+  if (role !== "SUPER_ADMIN" && existing.organizationId !== organizationId) {
+    return { error: "Access denied" };
+  }
+
+  await prisma.site.delete({
+    where: { id: siteId },
+  });
+
+  revalidatePath("/admin/settings/sites");
+  return { success: true };
+}

