+              <Edit className="h-4 w-4" />
+            </Link>
+          </Button>
+          <Button
+            size="sm"
+            variant="outline"
+            onClick={handleDelete}
+            disabled={isPending}
+            className="text-red-600 hover:text-red-700 hover:bg-red-50"
+          >
+            <Trash2 className="h-4 w-4" />
+          </Button>
+        </div>
+      </div>
+    </Card>
+  );
+}
+
+async function SiteList({ orgId }: { orgId: string }) {
+  const sites = await prisma.site.findMany({
+    where: { organizationId: orgId },
+    orderBy: [{ status: "asc" }, { name: "asc" }],
+  });
+  return (
+    <div className="space-y-3">
+      {sites.length === 0 ? (
+        <Card className="p-8 text-center">
+          <MapPin className="h-10 w-10 mx-auto text-[hsl(var(--muted-foreground))] mb-3" />
+          <p className="text-[hsl(var(--muted-foreground))]">No sites yet.</p>
+          <p className="text-sm text-[hsl(var(--muted-foreground))]">
+            Add your first jobsite or project below.
+          </p>
+        </Card>
+      ) : (
+        sites.map((site) => <SiteCard key={site.id} site={site} />)
+      )}
+    </div>
+  );
+}
+
+export default function SitesPage() {
+  const [showForm, setShowForm] = useState(false);
+
+  return (
+    <div className="space-y-6">
+      <div className="flex items-center justify-between">
+        <div>
+          <Link
+            href="/admin/settings"
+            className="text-sm text-[hsl(var(--muted-foreground))] hover:text-[hsl(var(--foreground))] mb-1 inline-block"
+          >
+            ← Settings
+          </Link>
+          <h1 className="text-2xl font-semibold">Sites / Projects</h1>
+        </div>
+        {!showForm && (
+          <Button onClick={() => setShowForm(true)}>
+            <Plus className="h-4 w-4 mr-1" />
+            Add Site
+          </Button>
+        )}
+      </div>
+
+      {showForm && (
+        <div className="mb-4">
+          <h2 className="text-sm font-medium mb-2">New Site</h2>
+          <SiteForm onCancel={() => setShowForm(false)} />
+        </div>
+      )}
+
+      <Suspense fallback={<div className="text-sm text-[hsl(var(--muted-foreground))]">Loading sites...</div>}>
+        <SiteListWrapper />
+      </Suspense>
+    </div>
+  );
+}
+
+async function SiteListWrapper() {
+  const session = await auth();
+  if (!session?.user?.organizationId) redirect("/login");
+  return <SiteList orgId={session.user.organizationId} />;
+}
diff --git a/src/lib/actions/sites.ts b/src/lib/actions/sites.ts
new file mode 100644
index 0000000..1fe3511
--- /dev/null
+++ b/src/lib/actions/sites.ts
@@ -0,0 +1,173 @@
+"use server";
+
+import { auth } from "@/lib/auth";
+import { prisma } from "@/lib/db";
+import { revalidatePath } from "next/cache";
+import { z } from "zod";
+import { Prisma } from "@prisma/client";
+import { Role } from "@prisma/client";
+
+const siteSchema = z.object({
+  name: z.string().min(1, "Name is required").max(255),
+  code: z.string().max(50).optional().nullable(),
+  address: z.string().max(500).optional().nullable(),
+  contactName: z.string().max(255).optional().nullable(),
+  contactPhone: z.string().max(50).optional().nullable(),
+  emergencyContact: z.string().max(500).optional().nullable(),
+  musterPoint: z.string().max(500).optional().nullable(),
+  openedAt: z.string().optional().nullable(),
+  closedAt: z.string().optional().nullable(),
+  notes: z.string().max(2000).optional().nullable(),
+});
+
+function canAccessOrg(session: { user: { role?: string; organizationId?: string } } | null, orgId: string): boolean {
+  if (!session?.user) return false;
+  if (session.user.role === "SUPER_ADMIN") return true;
+  return session.user.organizationId === orgId;
+}
+
+function requireOrgAdmin(session: { user: { role?: string; organizationId?: string } } | null, orgId: string): void {
+  if (!session?.user) throw new Error("Unauthorized");
+  if (session.user.role === "SUPER_ADMIN") return;
+  if (session.user.organizationId !== orgId) throw new Error("Forbidden: You can only manage sites for your own organization.");
+  if (session.user.role !== "ORG_ADMIN") throw new Error("Forbidden: Only Org Admins can manage sites.");
+}
+
+export async function createSite(prevState: { error?: string; success?: boolean } | null, formData: FormData) {
+  const session = await auth();
+  if (!session?.user?.organizationId) {
+    return { error: "You must be logged in to an organization." };
+  }
+
+  const rawData = {
+    name: formData.get("name") as string,
+    code: formData.get("code") as string || undefined,
+    address: formData.get("address") as string || undefined,
+    contactName: formData.get("contactName") as string || undefined,
+    contactPhone: formData.get("contactPhone") as string || undefined,
+    emergencyContact: formData.get("emergencyContact") as string || undefined,
+    musterPoint: formData.get("musterPoint") as string || undefined,
+    openedAt: formData.get("openedAt") as string || undefined,
+    closedAt: formData.get("closedAt") as string || undefined,
+    notes: formData.get("notes") as string || undefined,
+  };
+
+  const parsed = siteSchema.safeParse(rawData);
+  if (!parsed.success) {
+    return { error: parsed.error.errors[0].message };
+  }
+
+  const orgId = session.user.organizationId;
+  requireOrgAdmin(session, orgId);
+
+  try {
+    await prisma.site.create({
+      data: {
+        name: parsed.data.name!,
+        code: parsed.data.code ?? null,
+        address: parsed.data.address ?? null,
+        contactName: parsed.data.contactName ?? null,
+        contactPhone: parsed.data.contactPhone ?? null,
+        emergencyContact: parsed.data.emergencyContact ?? null,
+        musterPoint: parsed.data.musterPoint ?? null,
+        openedAt: parsed.data.openedAt ? new Date(parsed.data.openedAt) : null,
+        closedAt: parsed.data.closedAt ? new Date(parsed.data.closedAt) : null,
+        notes: parsed.data.notes ?? null,
+        organizationId: orgId,
+      },
+    });
+  } catch (e) {
+    if (e instanceof Prisma.PrismaClientKnownRequestError && e.code === "P2002") {
+      return { error: "A site with this name already exists in your organization." };
+    }
+    throw e;
+  }
+
+  revalidatePath("/admin/settings/sites");
+  return { success: true };
+}
+
+export async function updateSite(siteId: string, prevState: { error?: string; success?: boolean } | null, formData: FormData) {
+  const session = await auth();
+  if (!session?.user) return { error: "Unauthorized" };
+
+  const site = await prisma.site.findUnique({ where: { id: siteId }, select: { organizationId: true } });
+  if (!site) return { error: "Site not found" };
+
+  requireOrgAdmin(session, site.organizationId);
+
+  const rawData = {
+    name: formData.get("name") as string,
+    code: formData.get("code") as string || undefined,
+    address: formData.get("address") as string || undefined,
+    contactName: formData.get("contactName") as string || undefined,
+    contactPhone: formData.get("contactPhone") as string || undefined,
+    emergencyContact: formData.get("emergencyContact") as string || undefined,
+    musterPoint: formData.get("musterPoint") as string || undefined,
+    openedAt: formData.get("openedAt") as string || undefined,
+    closedAt: formData.get("closedAt") as string || undefined,
+    notes: formData.get("notes") as string || undefined,
+  };
+
+  const parsed = siteSchema.safeParse(rawData);
+  if (!parsed.success) {
+    return { error: parsed.error.errors[0].message };
+  }
+
+  try {
+    await prisma.site.update({
+      where: { id: siteId },
+      data: {
+        name: parsed.data.name!,
+        code: parsed.data.code ?? null,
+        address: parsed.data.address ?? null,
+        contactName: parsed.data.contactName ?? null,
+        contactPhone: parsed.data.contactPhone ?? null,
+        emergencyContact: parsed.data.emergencyContact ?? null,
+        musterPoint: parsed.data.musterPoint ?? null,
+        openedAt: parsed.data.openedAt ? new Date(parsed.data.openedAt) : null,
+        closedAt: parsed.data.closedAt ? new Date(parsed.data.closedAt) : null,
+        notes: parsed.data.notes ?? null,
+      },
+    });
+  } catch (e) {
+    if (e instanceof Prisma.PrismaClientKnownRequestError && e.code === "P2002") {
+      return { error: "A site with this name already exists in your organization." };
+    }
+    throw e;
+  }
+
+  revalidatePath("/admin/settings/sites");
+  revalidatePath(`/admin/settings/sites/${siteId}`);
+  return { success: true };
+}
+
+export async function setSiteStatus(siteId: string) {
+  const session = await auth();
+  if (!session?.user) throw new Error("Unauthorized");
+
+  const site = await prisma.site.findUnique({ where: { id: siteId }, select: { organizationId: true, status: true } });
+  if (!site) throw new Error("Site not found");
+
+  requireOrgAdmin(session, site.organizationId);
+
+  const newStatus = site.status === "ACTIVE" ? "ARCHIVED" : "ACTIVE";
+  await prisma.site.update({ where: { id: siteId }, data: { status: newStatus } });
+
+  revalidatePath("/admin/settings/sites");
+  revalidatePath(`/admin/settings/sites/${siteId}`);
+}
+
+export async function deleteSite(siteId: string) {
+  const session = await auth();
+  if (!session?.user) throw new Error("Unauthorized");
+
+  const site = await prisma.site.findUnique({ where: { id: siteId }, select: { organizationId: true } });
+  if (!site) throw new Error("Site not found");
+
+  requireOrgAdmin(session, site.organizationId);
+
+  await prisma.site.delete({ where: { id: siteId } });
+
+  revalidatePath("/admin/settings/sites");
+}

