+class ECDSASHA256 implements SignatureAlgorithm {
+  static const String _ecdsaSha256Uri =
+      'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256';
+
+  @override
+  String get algorithmName => _ecdsaSha256Uri;
+
+  @override
+  String getSignature(String xml, Uint8List signingKey,
+      [CalculateSignatureCallback? callback]) {
+    final pem = utf8.decode(signingKey);
+    final privateKey = _parsePrivateKey(pem);
+    final signer = ECDSASigner(SHA256Digest())
+      ..init(true, _PrivateKeyParameter(privateKey));
+    final signature = signer.generateSignature(utf8.encode(xml)) as ECSignature;
+    final result = _signatureToRaw(signature, privateKey);
+    if (callback != null) callback(null, result);
+    return result;
+  }
+
+  @override
+  bool verifySignature(String xml, Uint8List key, String signatureValue,
+      [ValidateSignatureCallback? callback]) {
+    final pem = utf8.decode(key);
+    final publicKey = _parsePublicKey(pem);
+    final signature = _rawToSignature(signatureValue, publicKey);
+    final verifier = ECDSASigner(SHA256Digest())
+      ..init(false, _PublicKeyParameter(publicKey));
+    final res = verifier.verifySignature(utf8.encode(xml), signature);
+    if (callback != null) callback(null, res);
+    return res;
+  }
+
+  AsymmetricKey _parsePrivateKey(String pem) {
+    final parser = ECKeyParser();
+    return parser.parsePrivateKeyFromPEMString(pem);
+  }
+
+  AsymmetricKey _parsePublicKey(String pem) {
+    final parser = ECKeyParser();
+    return parser.parsePublicKeyFromPEMString(pem);
+  }
+
+  String _signatureToRaw(ECSignature sig, AsymmetricKey privateKey) {
+    final domain = _getDomain(privateKey);
+    final byteLength = (domain.n.bitLength + 7) >> 3;
+    final r = _bigIntToBytes(sig.r, byteLength);
+    final s = _bigIntToBytes(sig.s, byteLength);
+    return base64Encode(r + s);
+  }
+
+  ECSignature _rawToSignature(String signatureValue, AsymmetricKey publicKey) {
+    final decoded = base64Decode(signatureValue);
+    final domain = _getDomain(publicKey);
+    final byteLength = (domain.n.bitLength + 7) >> 3;
+    if (decoded.length < byteLength * 2) {
+      final padded = List<int>.filled(byteLength * 2, 0);
+      padded.setRange(byteLength * 2 - decoded.length, byteLength * 2, decoded);
+      final r = _bytesToBigInt(padded.sublist(0, byteLength));
+      final s = _bytesToBigInt(padded.sublist(byteLength));
+      return ECSignature(r, s);
+    }
+    final r = _bytesToBigInt(decoded.sublist(0, byteLength));
+    final s = _bytesToBigInt(decoded.sublist(byteLength));
+    return ECSignature(r, s);
+  }
+
+  ECDomainParameters _getDomain(AsymmetricKey key) {
+    if (key is ECPrivateKey) {
+      return ECDomainParameters('P-256');
+    } else if (key is ECPublicKey) {
