+  List<int> _bigIntToBytes(BigInt value, int byteLength) {
+    final bytes = _bigIntToBytesUnpadded(value);
+    if (bytes.length < byteLength) {
+      final padded = List<int>.filled(byteLength, 0);
+      padded.setRange(byteLength - bytes.length, byteLength, bytes);
+      return padded;
+    }
+    return bytes;
+  }
+
+  List<int> _bigIntToBytesUnpadded(BigInt value) {
+    if (value == BigInt.zero) return [0];
+    final hex = value.toRadixString(16).toLowerCase();
+    final hexLen = hex.length;
+    if (hexLen % 2 != 0) {
+      return [int.parse(hex.substring(0, 1), radix: 16)] +
+          _hexToBytes(hex.substring(1));
+    }
+    return _hexToBytes(hex);
+  }
+
+  List<int> _hexToBytes(String hex) {
+    final bytes = <int>[];
+    for (var i = 0; i < hex.length; i += 2) {
+      bytes.add(int.parse(hex.substring(i, i + 2), radix: 16));
+    }
+    return bytes;
+  }
+
+  BigInt _bytesToBigInt(List<int> bytes) {
+    var hex = '';
+    for (final b in bytes) {
+      final h = b.toRadixString(16);
+      hex += h.length == 1 ? '0$h' : h;
+    }
+    return BigInt.parse(hex, radix: 16);
+  }
