+//Copyright (C) 2024 Potix Corporation. All Rights Reserved.
+//History: Thu Jan 01 00:00:00 CST 2024
+// Author: xml-crypto
+
+import 'dart:io';
+
+import 'package:xml_crypto/xml_crypto.dart';
+import 'package:test/test.dart';
+
+void main() {
+  group('ECDSA-SHA256 Tests', () {
+    test('should sign and verify XML with ECDSA-SHA256', () {
+      final xml =
+          '<Envelope xmlns="http://example.org"><Data Id="data">Test data</Data></Envelope>';
+
+      final sig = SignedXml()
+        ..addReference("//*[local-name()='Data']")
+        ..signingKey = File('test/static/ecdsa_private.pem').readAsBytesSync()
+        ..signatureAlgorithm =
+            'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'
+        ..computeSignature(xml);
+
+      final signedXml = sig.signedXml;
+      expect(signedXml, isNotEmpty);
+      expect(signedXml.contains('ecdsa-sha256'), isTrue);
+
+      // Verify the signature
+      final verify = SignedXml()
+        ..keyInfoProvider = FileKeyInfo('test/static/ecdsa_public.pem')
+        ..signatureAlgorithm =
+            'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256';
+      final isValid = verify.checkSignature(signedXml);
+      expect(isValid, isTrue);
+    });
+
+    test('should verify ECDSA-SHA256 signature with external signature', () {
+      final xml = File('test/static/ecdsa_signature.xml').readAsStringSync();
+
+      final verify = SignedXml()
+        ..keyInfoProvider = FileKeyInfo('test/static/ecdsa_public.pem')
+        ..signatureAlgorithm =
+            'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256';
+
+      final isValid = verify.checkSignature(xml);
+      expect(isValid, isTrue);
+    });
+
+    test('ECDSASHA256 algorithm should be registered in signatureAlgorithms',
+        () {
+      expect(
+        SignedXml.signatureAlgorithms
+            .containsKey('http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'),
+        isTrue,
+      );
+    });
+
+    test('ECDSASHA256 should have correct algorithm name', () {
+      final ecdsa = ECDSASHA256();
+      expect(ecdsa.algorithmName,
+          'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256');
+    });
+
+    test('ECDSA signature should be Base64 encoded raw r||s bytes', () {
+      final xml = '<Data>Test</Data>';
+      final sig = ECDSASHA256();
+      final signature = sig.getSignature(
+          xml, File('test/static/ecdsa_private.pem').readAsBytesSync());
+
+      // ECDSA P-256 raw signature should be 64 bytes (32 for r + 32 for s)
+      final decoded = signature;
+      // The signature is Base64 encoded, so decoded length should be 64 bytes
+      expect(decoded.length > 60, isTrue); // Base64 encoded 64 bytes is ~88 chars
+    });
+
+    test('should accept non-standard signatures with missing leading zeros',
+        () {
+      // This tests that the verification logic handles signatures that don't
+      // have full-length padding for r and s components
+      final ecdsa = ECDSASHA256();
+
+      // Create a signature and then manually modify it to remove leading zeros
+      final xml = '<Data>Test non-standard</Data>';
+      final signature = ecdsa.getSignature(
+          xml, File('test/static/ecdsa_private.pem').readAsBytesSync());
+
+      // The verifySignature method should handle non-standard signatures
+      final isValid = ecdsa.verifySignature(
+          xml, File('test/static/ecdsa_public.pem').readAsBytesSync(), signature);
+      expect(isValid, isTrue);
+    });
+  });
+}
