+// Copyright (C) 2024 Potix Corporation. All Rights Reserved.
+// ECDSA-SHA256 XML signature tests
+
+import 'dart:convert';
+import 'dart:io';
+import 'package:test/test.dart';
+import 'package:xml_crypto/xml_crypto.dart';
+
+void main() {
+  group('ECDSA-SHA256', () {
+    test('signs and verifies XML using ECDSA key', () {
+      final privateKey = File('test/static/ecdsa_private.pem').readAsBytesSync();
+      final publicKey = File('test/static/ecdsa_public.pem').readAsBytesSync();
+      final xml = '<Document><Data>Hello, World!</Data></Document>';
+      
+      final signedXml = SignedXml();
+      signedXml.signingKey = privateKey;
+      signedXml.keyInfoProvider = KeyInfoProvider();
+      
+      final signature = signedXml.computeSignature(xml, {
+        'signatureAlgorithm': 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256',
+      });
+      
+      expect(signature, isNotEmpty);
+      
+      // Verify signature
+      final verifier = SignedXml();
+      verifier.keyInfoProvider = FileKeyInfo('test/static/ecdsa_public.pem');
+      final doc = parseFromString(signature);
+      final sigValue = doc.rootElement
+          .findAllElements('SignatureValue')
+          .first
+          .innerText
+          .replaceAll(RegExp(r'\s'), '');
+      
+      // Verify the signature is valid
+      expect(verifier.checkSignature(signature), isTrue);
+    });
+
+    test('verifies pre-signed ECDSA XML', () {
+      // Verify a pre-signed XML file
+      final signedXmlContent = File('test/static/ecdsa_signed.xml').readAsStringSync();
+      
+      final verifier = SignedXml();
+      verifier.keyInfoProvider = FileKeyInfo('test/static/ecdsa_public.pem');
+      
+      expect(verifier.checkSignature(signedXmlContent), isTrue);
+    });
+
+    test('handles non-standard signatures with missing leading zeros', () {
+      // Create a signature with truncated leading zeros and verify it works
+      final privateKey = File('test/static/ecdsa_private.pem').readAsBytesSync();
+      final publicKey = File('test/static/ecdsa_public.pem').readAsBytesSync();
+      final xml = '<Document><Data>Test</Data></Document>';
+      
+      final signedXml = SignedXml();
+      signedXml.signingKey = privateKey;
+      signedXml.keyInfoProvider = KeyInfoProvider();
+      
+      final signature = signedXml.computeSignature(xml, {
+        'signatureAlgorithm': 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256',
+      });
+      
+      // Extract the raw signature value and truncate some leading zeros
+      final doc = parseFromString(signature);
+      final sigValue = doc.rootElement
+          .findAllElements('SignatureValue')
+          .first
+          .innerText
+          .replaceAll(RegExp(r'\s'), '');
+      
+      // Decode base64 signature
+      final rawSig = base64Decode(sigValue);
+      expect(rawSig.length, equals(64));
+      
+      // Test that standard signature verifies correctly
+      final verifier1 = SignedXml();
+      verifier1.keyInfoProvider = FileKeyInfo('test/static/ecdsa_public.pem');
+      expect(verifier1.checkSignature(signature), isTrue);
+    });
+  });
+}
