+  const home = process.env.HOME ?? '';
+  const paths = [
+    resolve(home, '.claude/plugins/cache/circuit-next/circuit', version),
+    resolve(home, '.claude/plugins/user/circuit-next/circuit', version),
+  ];
+  for (const p of paths) {
+    if (existsSync(p)) return p;
+  }
+  return null;
+}
