+  if (!existsSync(targetRoot)) return { status: 'missing' };
+  if (!statSync(targetRoot).isDirectory()) return { status: 'stale', details: 'target is not a directory' };
+
+  const sourceFiles = walkOwnedFiles(sourceRoot);
+  const targetFiles = walkOwnedFiles(targetRoot);
