+  const circuitHookFile = resolve(hooksDir, 'circuit.json');
+  const circuitHookYaml = resolve(hooksDir, 'circuit.yaml');
+  const circuitHookYml = resolve(hooksDir, 'circuit.yml');
+  
+  let hookConfig = null;
+  let hookSource = null;
+  
+  for (const hookFile of [circuitHookFile, circuitHookYaml, circuitHookYml]) {
+    if (existsSync(hookFile)) {
+      try {
+        hookConfig = readJson(hookFile);
+        hookSource = hookFile;
+        break;
+      } catch {
+        // try next format
+      }
+    }
+  }
+
+  if (!hookConfig) {
+    return { status: 'missing' };
+  }
+
+  // Check for duplicate Circuit hooks
+  const circuitEntries = [];
+  if (hookConfig.commands) {
+    for (const cmd of hookConfig.commands) {
+      if (cmd.command && cmd.command.includes && cmd.command.includes('circuit')) {
+        circuitEntries.push(cmd);
+      }
+    }
+  }
+
+  // Check launcher binary
+  const launcherPath = resolve(circuitDir, 'bin', 'circuit-next');
+  const launcherExists = existsSync(launcherPath);
