+  if (circuitEntries.length > 1) {
+    return { 
+      status: 'invalid', 
+      details: `duplicate Circuit hooks: ${circuitEntries.length} entries found`,
+      hook_count: circuitEntries.length,
+    };
+  }
+
+  if (!launcherExists) {
+    return { 
+      status: 'invalid', 
+      details: 'launcher binary missing: bin/circuit-next',
+    };
+  }
+
+  if (circuitEntries.length === 0) {
