--- a/scripts/plugin-package-tree.mjs
+++ b/scripts/plugin-package-tree.mjs
@@ -0,0 +1,146 @@
+import { createHash } from 'node:crypto';
+import { existsSync, readFileSync, readdirSync, statSync } from 'node:fs';
+import { join, resolve } from 'node:path';
+
+const OWNED_ROOTS = new Set([
+  '.claude-plugin',
+  '.codex-plugin',
+  'commands',
+  'flows',
+  'hooks',
+  'runtime',
+  'scripts',
+  'skills',
+]);
+
+function normalizeRelativePath(path) {
+  return path
+    .split(/[\\/]+/)
+    .filter(Boolean)
+    .join('/');
+}
+
+export function isPackageOwnedFile(path) {
+  const normalized = normalizeRelativePath(path);
+  if (normalized === 'README.md') return true;
+  const [head] = normalized.split('/');
+  return head !== undefined && OWNED_ROOTS.has(head);
+}
+
+function walkFiles(root) {
+  if (!existsSync(root)) return [];
+  if (!statSync(root).isDirectory()) return [];
+  const files = [];
+  const stack = [''];
+  while (stack.length > 0) {
+    const relDir = stack.pop() ?? '';
+    const absDir = resolve(root, relDir);
+    for (const entry of readdirSync(absDir, { withFileTypes: true })) {
+      const relPath = join(relDir, entry.name);
+      if (entry.isDirectory()) {
+        stack.push(relPath);
+      } else if (entry.isFile()) {
+        files.push(normalizeRelativePath(relPath));
+      }
+    }
+  }
+  return files.sort();
+}
+
+export function walkPackageFiles(root) {
+  return walkFiles(root).filter(isPackageOwnedFile);
+}
+
+function digestFile(path) {
+  return createHash('sha256').update(readFileSync(path)).digest('hex');
+}
+
+function fileMap(root) {
+  return new Map(walkPackageFiles(root).map((file) => [file, digestFile(resolve(root, file))]));
+}
+
+export function packageTreeStatus(source, target) {
+  const sourceRoot = resolve(source);
+  const targetRoot = resolve(target);
+  const sourceFiles = fileMap(sourceRoot);
+
+  if (!existsSync(targetRoot)) {
+    return {
+      status: 'missing',
+      source: sourceRoot,
+      target: targetRoot,
+      missing: [...sourceFiles.keys()],
+      stale: [],
+      extra_owned_files: [],
+      source_file_count: sourceFiles.size,
+      target_owned_file_count: 0,
+    };
+  }
+
+  if (!statSync(targetRoot).isDirectory()) {
+    return {
+      status: 'stale',
+      source: sourceRoot,
+      target: targetRoot,
+      missing: [...sourceFiles.keys()],
+      stale: [],
+      extra_owned_files: [],
+      source_file_count: sourceFiles.size,
+      target_owned_file_count: 0,
+    };
+  }
+
+  const targetFiles = fileMap(targetRoot);
+  const missing = [];
+  const stale = [];
+  const extraOwnedFiles = [];
+
