+        prim_rotations: Vec<[[i32; 3]; 3]>,
+        prim_translations: Vec<[f64; 3]>,
+        basis: Option<[[f64; 3]; 3]>,
+        setting: Option<PyLayerSetting>,
+        epsilon: f64,
